Let $k\in\naturals$, and let $n_1 \leq n_2 \leq \ldots \leq n_k$ be natural numbers.
Let $\Gr{G} = \CoG{n_1,n_2, \dots, n_k}$ be a complete multipartite graph on $n = n_1 + \ldots n_k$
vertices. Then,
\begin{itemize}
\item $\Gr{G}$ has one positive eigenvalue, i.e., $\lambda_1(\Gr{G}) > 0$ and $\lambda_2(\Gr{G})\le 0$.
\item $\Gr{G}$ has $0$ as an eigenvalue with multiplicity $n-k$.
\item $\Gr{G}$ has $k-1$ negative eigenvalues, and
\begin{align}
n_1 \leq -\lambda_{n-k+2}(\Gr{G}) \leq n_2 \leq -\lambda_{n-k+3}(\Gr{G}) \le n_3 \leq \ldots \leq n_{k-1} \leq -\lambda_{n}(\Gr{G}) \le n_{k}.
\end{align}
\end{itemize}

